// ==UserScript==// @name        Remove Hacking With Swift Navbar and skybar// @description Remove Hacking With Swift Navbar and skybar// @match *://www.hackingwithswift.com/* // // ==/UserScript==(function() &#123;    &#x27;use strict&#x27;;        function removeNavbarAndSkybar()&#123;        var mAds=document.querySelectorAll(&quot;.navbar&quot;),i;        for(i=0;i&lt;mAds.length;i++)&#123;            var mAd=mAds[i];            mAd.remove();        &#125;        var list=document.querySelectorAll(&quot;#hws-latest-tutorial&quot;);        for(i=0;i&lt;list.length;i++)&#123;            let item = list[i];            item.remove();        &#125;    &#125;        window.addEventListener(&#x27;load&#x27;, function() &#123;        removeNavbarAndSkybar();    &#125;, false);&#125;)();


