iOS RC4加密iOS RC4加密的实现，要注意加密后生成字符串的步骤，有些要求是base64加密后输出，有些要求是字节数组转16进制字符串输出，所以要特别注意。


代码如下：
// rc4加密- (NSString *)rc4Encode:(NSString *)aInput key:(NSString *)aKey &#123;    NSMutableArray *iS = [[NSMutableArray alloc] initWithCapacity:256];        NSMutableArray *iK = [[NSMutableArray alloc] initWithCapacity:256];        for (int i= 0; i&lt;256; i++) &#123;            [iS addObject:[NSNumber numberWithInt:i]];        &#125;        int j=1;        for (short i=0; i&lt;256; i++) &#123;            UniChar c = [aKey characterAtIndex:i%aKey.length];            [iK addObject:[NSNumber numberWithChar:c]];        &#125;        j=0;        for (int i=0; i&lt;256; i++) &#123;            int is = [[iS objectAtIndex:i] intValue];            UniChar ik = (UniChar)[[iK objectAtIndex:i] charValue];            j = (j + is + ik)%256;            NSNumber *temp = [iS objectAtIndex:i];            [iS replaceObjectAtIndex:i withObject:[iS objectAtIndex:j]];            [iS replaceObjectAtIndex:j withObject:temp];        &#125;        int i=0;        j=0;        Byte byteBuffer[aInput.length];        for (short x=0; x&lt;[aInput length]; x++) &#123;            i = (i+1)%256;            int is = [[iS objectAtIndex:i] intValue];            j = (j+is)%256;            int is_i = [[iS objectAtIndex:i] intValue];            int is_j = [[iS objectAtIndex:j] intValue];            int t = (is_i+is_j) % 256;            // 这里需要注意，原版这里是先取值，再交换位置，但是有问题，应该先交换位置，再取值！！！            [iS exchangeObjectAtIndex:i withObjectAtIndex:j];            int iY = [[iS objectAtIndex:t] intValue];            UniChar ch = (UniChar)[aInput characterAtIndex:x];            UniChar ch_y = ch^iY;            byteBuffer[x] = ch_y;        &#125;        // 字节数组转16进制字符串输出    NSString *resultString = [self stringFromByte:byteBuffer length:aInput.length];    //    NSData *adata = [[NSData alloc] initWithBytes:byteBuffer length:aInput.length];//    NSString *string = [adata base64EncodedStringWithOptions:0]; // 以base64的加密结果输出    return resultString;&#125;//rc4解密- (NSString *)rc4Decode:(NSString *)data key:(NSString*)secret&#123;    // 如果是16进制字符串    NSData *raw = [self ByteDataFromString:data];        // 如果是base64加密后字符串//    NSData *raw = [[NSData alloc] initWithBase64EncodedString:data options:0];        int cipherLength = (int)raw.length;    UInt8 *cipher = malloc(cipherLength);    [raw getBytes:cipher length:cipherLength];    NSData *kData = [secret dataUsingEncoding:NSUTF8StringEncoding];    int keyLength = (int)kData.length;    UInt8 *kBytes = malloc(kData.length);    [kData getBytes:kBytes length:kData.length];    UInt8 *decipher = malloc(cipherLength + 1);    UInt8 iS[256];    UInt8 iK[256];    int i;    for (i = 0; i &lt; 256; i++)&#123;        iS[i] = i;        iK[i] = kBytes[i % keyLength];    &#125;    int j = 0;    for (i = 0; i &lt; 256; i++)&#123;        int is = iS[i];        int ik = iK[i];        j = (j + is + ik)% 256;        UInt8 temp = iS[i];        iS[i] = iS[j];        iS[j] = temp;    &#125;    int q = 0;    int p = 0;    for (int x = 0; x &lt; cipherLength; x++)&#123;        q = (q + 1)% 256;        p = (p + iS[q])% 256;        int k = iS[p];        iS[p] = iS[q];        iS[q] = k;        k = iS[(iS[q] + iS[p])% 256];        decipher[x] = cipher[x] ^ k;    &#125;    free(kBytes);    decipher[cipherLength] = &#x27;\0&#x27;;    return @((char *)decipher);&#125;// 字节数组转- (NSString *)stringFromByte:(Byte *)byteBuffer length:(NSInteger)length &#123;    NSMutableString *hexString = [[NSMutableString alloc] init];    for (int i = 0; i &lt; length; i++) &#123;        [hexString appendString:[NSString stringWithFormat:@&quot;%0.2hhx&quot;, byteBuffer[i]]];    &#125;    return [hexString uppercaseString];&#125;- (NSData *)ByteDataFromString:(NSString *)targetStr &#123;    NSInteger len = [targetStr length] / 2;    // Target length    unsigned char *buf = malloc(len);    unsigned char *whole_byte = buf;    char byte_chars[3] = &#123;&#x27;\0&#x27;,&#x27;\0&#x27;,&#x27;\0&#x27;&#125;;    int i;    for (i=0; i &lt; [targetStr length] / 2; i++) &#123;        byte_chars[0] = [targetStr characterAtIndex:i*2];        byte_chars[1] = [targetStr characterAtIndex:i*2+1];        *whole_byte = strtol(byte_chars, NULL, 16);        whole_byte++;    &#125;    NSData *data = [NSData dataWithBytes:buf length:len];    free( buf );    return data;&#125;


参考iOS,objectC,RC4加密解密方法iOS 二进制数组转成16进制字符串

iOS StatusBar 设置背景最近遇到设置StatusBar的问题，在NavigationController出来的界面设置StatusBar后一直不生效，印象中遇到过此类的问题，但是没有记录总结，还是花费了一点时间来找到原因，所以赶紧记录一下。


全局设置StatusBar的全局设置，需要首先在info.plist中设置View controller-based status bar appearance为NO，关掉按界面设置status bar 显示。
显示/隐藏方法一：在Target下的Deployment Info中不勾选/勾选Hide status bar

方法二：代码设置
[UIApplication sharedApplication].statusBarHidden = YES;


设置方法一：在Target下的Deployment Info中设置Status Bar Style

方法二：代码设置
[UIApplication sharedApplication].statusBarStyle = UIStatusBarStyleLightContent;

界面单独设置首先在info.plist中设置View controller-based status bar appearance为YES，打开按界面设置status bar 显示。
普通的ViewController设置：
- (UIStatusBarStyle)preferredStatusBarStyle &#123;    return UIStatusBarStyleDefault;&#125;

如果是UINavigaitonController，则需要添加一个继承自UINavigationController的子类，在子类中设置如下代码，使用子类来控制。或者添加UINavigaitonController的Category，在Category中设置如下代码
原因是：UIViewController嵌套在UINavigaitonController中时，会优先调用UINavigationController的preferredStatusBarStyle，所以直接在UIViewController中设置是不生效的。
- (UIStatusBarStyle)preferredStatusBarStyle &#123;    return [self.topViewController preferredStatusBarStyle];&#125;- (UIViewController *)childViewControllerForStatusBarStyle &#123;    return self.topViewController;&#125;

问题modal出来的viewController设置了prefersStatusBarHidden不生效的问题，需要设置modalPresentationCapturesStatusBarAppearance为YES；
@implementation TargetViewController- (instancetype)init &#123;    self = [super init];    if (self) &#123;        self.modalPresentationStyle = UIModalPresentationOverFullScreen;        self.modalPresentationCapturesStatusBarAppearance = YES;    &#125;    return self;&#125;- (BOOL)prefersStatusBarHidden &#123;    return YES;&#125;

