当键盘弹出时，有可能会遮盖住输入框，之前我采用把View放到scrollView上来处理，但是后来发现，让View跟着键盘动起来效果更好

// 首先注册通知，弹出键盘和键盘回收两个// 弹出键盘时view向上偏移，避免遮盖输入框[[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];[[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];// 然后实现通知的方法#pragma mark - keyboard notification -- (void)keyboardWillShow:(NSNotification *)note &#123;    NSDictionary *info = [note userInfo];    // keyboardHeight 为键盘高度    CGSize keyboardSize = [[info objectForKey:UIKeyboardFrameEndUserInfoKey] CGRectValue].size;    [self animateViewWithKeyboardHeight: keyboardSize.height];&#125;- (void)keyboardWillHide:(NSNotification *)note &#123;    [self animateViewWithKeyboardHeight: 0.0];&#125;- (void)animateViewWithKeyboardHeight:(CGFloat)keyboardHeight&#123;    NSTimeInterval animationDuration = 0.3f;    CGFloat width = self.bounds.size.width;    CGFloat height = self.bounds.size.height;    // 保持键盘和输入框底部view至少有-10的间距，这里的间距自己来定    CGFloat space = -10;    CGFloat topSize = 0.0;    CGFloat viewH = _bottomBackView.frame.size.height + _bottomBackView.frame.origin.y + space; // 得到view底部的y    CGFloat deviceH = self.bounds.size.height;    // 屏幕高度 - （view底部的y + 键盘的高度）, 如果&gt;=0，则说明距离足够，设置view.origin.y = 0；否则则说明view需要上移    CGFloat animateH = deviceH - viewH - keyboardHeight;    if (animateH &gt;= 0) &#123;        topSize = 0;        CGRect toRect = CGRectMake(0, topSize, width, height);        self.frame = toRect;    &#125; else &#123;        topSize = animateH;        CGRect toRect = CGRectMake(0, topSize, width, height);        [UIView animateWithDuration:animationDuration animations:^&#123;            self.frame = toRect;        &#125;];    &#125;&#125;// 最后注销通知- (void)dealloc &#123;    [[NSNotificationCenter defaultCenter] removeObserver:self name:UIKeyboardWillShowNotification object:nil];    [[NSNotificationCenter defaultCenter] removeObserver:self name:UIKeyboardWillHideNotification object:nil];&#125;

